document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("mobile-menu-btn"),t=document.getElementById("mobile-menu");e&&t&&e.addEventListener("click",()=>{t.classList.toggle("hidden")});const n=Array.from(document.querySelectorAll(".parallax-element"));let r=!1;if(n.length){const e=()=>{const t=.3*window.pageYOffset;n.forEach(e=>{e.style.transform=`translate3d(0, ${t}px, 0)`}),r=!1};window.addEventListener("scroll",()=>{r||(r=!0,window.requestAnimationFrame(e))},{passive:!0})}document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",t=>{t.preventDefault();const n=document.querySelector(e.getAttribute("href"));n&&n.scrollIntoView({behavior:"smooth",block:"start"})})});const o=document.querySelectorAll("[data-region]"),s=document.querySelectorAll(".experience-card"),i=document.getElementById("reset-experiences");o.forEach(e=>{e.addEventListener("click",()=>{const t=e.dataset.region;s.forEach(e=>{e.dataset.region===t?e.classList.remove("hidden"):e.classList.add("hidden")}),i&&i.classList.remove("hidden")});const t=e.querySelector(".tooltip");t&&(e.addEventListener("mouseenter",()=>{t.classList.remove("opacity-0"),t.classList.add("opacity-100")}),e.addEventListener("mouseleave",()=>{t.classList.add("opacity-0"),t.classList.remove("opacity-100")}))}),i&&i.addEventListener("click",()=>{s.forEach(e=>e.classList.remove("hidden")),i.classList.add("hidden")})});
